//! Pure Rust embedding via fastembed (ONNX Runtime, no Python).
//!
//! Downloads model on first use (~25MB for AllMiniLML6V2).
//! Produces 384-dim embeddings in-process with zero external dependencies.

use fastembed::{EmbeddingModel, InitOptions, TextEmbedding};
use std::sync::OnceLock;
use tokio::sync::Mutex;
use tracing::{info, warn};

/// Shared model instance — loaded once, reused across calls.
static MODEL: OnceLock<Mutex<TextEmbedding>> = OnceLock::new();

fn get_model() -> &'static Mutex<TextEmbedding> {
    MODEL.get_or_init(|| {
        info!("loading embedding model AllMiniLML6V2...");
        let model = TextEmbedding::try_new(
            InitOptions::new(EmbeddingModel::AllMiniLML6V2).with_show_download_progress(true),
        )
        .expect("failed to load embedding model");
        info!("embedding model loaded (384 dims)");
        Mutex::new(model)
    })
}

/// Embed a single text. Returns 384-dim f32 vector.
pub async fn embed(text: &str) -> Vec<f32> {
    let model = get_model();
    let mut guard = model.lock().await;
    match guard.embed(vec![text.to_string()], None) {
        Ok(mut results) if !results.is_empty() => results.remove(0),
        Ok(_) => {
            warn!("embedding returned empty results");
            vec![0.0; 384]
        }
        Err(e) => {
            warn!(error = %e, "embedding failed");
            vec![0.0; 384]
        }
    }
}

/// Embed multiple texts in batch. More efficient than individual calls.
pub async fn embed_batch(texts: &[String]) -> Vec<Vec<f32>> {
    if texts.is_empty() {
        return vec![];
    }
    let model = get_model();
    let mut guard = model.lock().await;
    match guard.embed(texts, None) {
        Ok(results) => results,
        Err(e) => {
            warn!(error = %e, "batch embedding failed");
            texts.iter().map(|_| vec![0.0; 384]).collect()
        }
    }
}

/// Embedding dimension (AllMiniLML6V2 = 384).
pub const fn embedding_dim() -> usize {
    384
}

#[cfg(test)]
mod tests {
    use super::*;

    #[tokio::test]
    async fn embed_produces_384_dims() {
        let v = embed("test convergio knowledge store").await;
        assert_eq!(v.len(), 384);
        // Should not be all zeros (model loaded successfully)
        let nonzero = v.iter().any(|x| *x != 0.0);
        assert!(nonzero, "embedding should have non-zero values");
    }

    #[tokio::test]
    async fn similar_texts_have_high_similarity() {
        let a = embed("rate limiter fix for authenticated agents").await;
        let b = embed("fixing the rate limit for auth users").await;
        let c = embed("chocolate cake recipe with vanilla frosting").await;

        let sim_ab = cosine(&a, &b);
        let sim_ac = cosine(&a, &c);
        assert!(
            sim_ab > sim_ac,
            "similar texts should score higher: ab={sim_ab:.3} ac={sim_ac:.3}"
        );
    }

    fn cosine(a: &[f32], b: &[f32]) -> f32 {
        let dot: f32 = a.iter().zip(b).map(|(x, y)| x * y).sum();
        let na: f32 = a.iter().map(|x| x * x).sum::<f32>().sqrt();
        let nb: f32 = b.iter().map(|x| x * x).sum::<f32>().sqrt();
        if na == 0.0 || nb == 0.0 {
            0.0
        } else {
            dot / (na * nb)
        }
    }
}

//! Extension trait implementation for convergio-knowledge.

use std::path::PathBuf;
use std::sync::{Arc, OnceLock};

use convergio_db::pool::ConnPool;
use convergio_types::events::{DomainEvent, EventFilter, EventKind};
use convergio_types::extension::{
    AppContext, Extension, Health, McpToolDef, Metric, Migration, ScheduledTask,
};
use convergio_types::manifest::{Capability, Manifest, ModuleKind};

use crate::routes::{knowledge_routes, KnowledgeState};
use crate::store::LanceVectorStore;

pub struct KnowledgeExtension {
    pool: ConnPool,
    lance_path: PathBuf,
    store: OnceLock<Option<Arc<LanceVectorStore>>>,
}

impl KnowledgeExtension {
    pub fn new(pool: ConnPool) -> Self {
        let lance_path = dirs::home_dir()
            .unwrap_or_else(|| PathBuf::from("."))
            .join(".convergio/data/knowledge.lance");
        Self {
            pool,
            lance_path,
            store: OnceLock::new(),
        }
    }

    fn get_store(&self) -> Option<Arc<LanceVectorStore>> {
        self.store
            .get_or_init(|| {
                let path = self.lance_path.clone();
                // Spawn a separate thread to init LanceDB — avoids tokio runtime nesting issues
                let result = std::thread::spawn(move || {
                    let rt = tokio::runtime::Builder::new_current_thread()
                        .enable_all()
                        .build()
                        .ok()?;
                    rt.block_on(LanceVectorStore::open(&path)).ok()
                })
                .join()
                .ok()
                .flatten();
                match result {
                    Some(s) => Some(Arc::new(s)),
                    None => {
                        tracing::warn!("lance store unavailable — knowledge search disabled");
                        None
                    }
                }
            })
            .clone()
    }

    fn state(&self) -> Arc<KnowledgeState> {
        Arc::new(KnowledgeState {
            pool: self.pool.clone(),
            store: self.get_store(),
        })
    }
}

impl Extension for KnowledgeExtension {
    fn manifest(&self) -> Manifest {
        Manifest {
            id: "convergio-knowledge".to_string(),
            description: "Vector knowledge store — semantic memory for agents via embeddings"
                .to_string(),
            version: env!("CARGO_PKG_VERSION").to_string(),
            kind: ModuleKind::Platform,
            provides: vec![
                Capability {
                    name: "knowledge-vectors".to_string(),
                    version: "1.0.0".to_string(),
                    description: "Embedding-based semantic search over agent knowledge".to_string(),
                },
                Capability {
                    name: "knowledge-api".to_string(),
                    version: "1.0.0".to_string(),
                    description: "REST API for knowledge search and write".to_string(),
                },
            ],
            requires: vec![],
            agent_tools: vec![],
            required_roles: vec!["orchestrator".into(), "all".into()],
        }
    }

    fn migrations(&self) -> Vec<Migration> {
        vec![]
    }

    fn routes(&self, _ctx: &AppContext) -> Option<axum::Router> {
        Some(knowledge_routes(self.state()))
    }

    fn health(&self) -> Health {
        let Some(store) = self.get_store() else {
            return Health::Ok;
        };
        let ok = std::thread::spawn(move || {
            let rt = tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build()
                .ok()?;
            rt.block_on(store.stats()).ok()
        })
        .join()
        .ok()
        .flatten();
        if ok.is_some() {
            Health::Ok
        } else {
            Health::Degraded {
                reason: "lance stats failed".into(),
            }
        }
    }

    fn metrics(&self) -> Vec<Metric> {
        let Some(store) = self.get_store() else {
            return vec![];
        };
        let count = std::thread::spawn(move || {
            let rt = tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build()
                .ok()?;
            rt.block_on(store.stats())
                .ok()
                .map(|s| s.total_entries as f64)
        })
        .join()
        .ok()
        .flatten()
        .unwrap_or(0.0);
        vec![Metric {
            name: "knowledge_entries_total".to_string(),
            value: count,
            labels: vec![],
        }]
    }

    fn subscriptions(&self) -> Vec<EventFilter> {
        vec![EventFilter {
            kind_prefix: Some("Task".to_string()),
            org: None,
            actor: None,
        }]
    }

    fn on_event(&self, event: &DomainEvent) {
        if let EventKind::TaskCompleted { task_id } = &event.kind {
            if let Some(store) = self.get_store() {
                crate::hooks::on_task_completed(&self.pool, store, *task_id)
            };
        }
    }

    fn scheduled_tasks(&self) -> Vec<ScheduledTask> {
        vec![
            ScheduledTask {
                name: "knowledge-commit-sync",
                cron: "*/15 * * * *",
            },
            ScheduledTask {
                name: "knowledge-auto-prune",
                cron: "0 3 * * *", // daily at 3 AM
            },
        ]
    }

    fn on_scheduled_task(&self, task_name: &str) {
        if task_name == "knowledge-commit-sync" {
            if let Some(store) = self.get_store() {
                crate::hooks::sync_recent_commits(store)
            };
        }
        if task_name == "knowledge-auto-prune" {
            if let Some(store) = self.get_store() {
                let store = store.clone();
                tokio::spawn(async move {
                    let req = crate::pruning::PruneRequest {
                        max_age_days: None,
                        source_type: None,
                        dry_run: false,
                    };
                    let report = crate::pruning::prune(&store, &req).await;
                    tracing::info!(
                        stale = report.stale_removed,
                        dedup = report.duplicates_removed,
                        source_dedup = report.source_dedup_removed,
                        total = report.total_removed,
                        "auto-prune completed"
                    );
                });
            };
        }
    }

    fn mcp_tools(&self) -> Vec<McpToolDef> {
        crate::mcp_defs::knowledge_tools()
    }
}

//! Hooks — auto-embed task summaries and commit messages.
//!
//! - `on_task_completed`: fires on TaskCompleted domain event,
//!   reads the task summary from DB and embeds it.
//! - `sync_recent_commits`: scheduled task that scans recent git
//!   commits and embeds their messages.

use std::sync::Arc;

use convergio_db::pool::ConnPool;
use tracing::{info, warn};

use crate::store::LanceVectorStore;

/// Called when a TaskCompleted event fires.
/// Reads the task summary and writes it to the knowledge store.
pub fn on_task_completed(pool: &ConnPool, store: Arc<LanceVectorStore>, task_id: i64) {
    let conn = match pool.get() {
        Ok(c) => c,
        Err(e) => {
            warn!(task_id, error = %e, "knowledge hook: db error");
            return;
        }
    };

    let row: Result<(String, Option<String>, Option<String>), _> = conn.query_row(
        "SELECT title, summary, notes FROM tasks WHERE id = ?1",
        [task_id],
        |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?)),
    );

    let (title, summary, notes) = match row {
        Ok(r) => r,
        Err(e) => {
            warn!(task_id, error = %e, "task not found for knowledge embed");
            return;
        }
    };

    let content = format!(
        "Task completed: {title}\n{}{}",
        summary
            .as_deref()
            .map(|s| format!("Summary: {s}\n"))
            .unwrap_or_default(),
        notes
            .as_deref()
            .map(|n| format!("Notes: {n}\n"))
            .unwrap_or_default(),
    );

    let source_id = format!("task-{task_id}");
    tokio::spawn(async move {
        let embedding = crate::embedder::embed(&content).await;
        match store
            .insert(
                &content, "task", &source_id, None, None, None, "org", &embedding,
            )
            .await
        {
            Ok(id) => info!(id, task_id, "task knowledge embedded"),
            Err(e) => warn!(task_id, error = %e, "embed task failed"),
        }
    });
}

/// Sync recent git commits — called on schedule (every 15 min).
/// Reads the repo's recent commits and embeds their messages.
pub fn sync_recent_commits(store: Arc<LanceVectorStore>) {
    let repo_root = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
    let output = match std::process::Command::new("git")
        .args(["log", "--oneline", "-20", "--format=%H|%s"])
        .current_dir(&repo_root)
        .output()
    {
        Ok(o) if o.status.success() => String::from_utf8_lossy(&o.stdout).to_string(),
        Ok(o) => {
            let stderr = String::from_utf8_lossy(&o.stderr);
            warn!(error = %stderr, "git log failed");
            return;
        }
        Err(e) => {
            warn!(error = %e, "git not available");
            return;
        }
    };

    let commits: Vec<(String, String)> = output
        .lines()
        .filter_map(|line| {
            let (hash, msg) = line.split_once('|')?;
            Some((hash.to_string(), msg.to_string()))
        })
        .collect();

    if commits.is_empty() {
        return;
    }

    tokio::spawn(async move {
        let mut embedded = 0u32;
        for (hash, msg) in &commits {
            let exists = store.count_by_source("commit", hash).await.unwrap_or(0);
            if exists > 0 {
                continue;
            }
            let embedding = crate::embedder::embed(msg).await;
            if store
                .insert(msg, "commit", hash, None, None, None, "org", &embedding)
                .await
                .is_ok()
            {
                embedded += 1;
            }
        }
        if embedded > 0 {
            info!(embedded, "commit knowledge synced");
        }
    });
}

